// app/admin/catalog/sync-form.tsx
"use client";

import { useActionState } from "react";

type SyncResult = { success: boolean; message: string } | null;

export function SyncForm({
  syncAction,
}: {
  syncAction: (
    prevState: SyncResult,
    formData: FormData,
  ) => Promise<SyncResult>;
}) {
  const [state, formAction, isPending] = useActionState<SyncResult, FormData>(
    syncAction,
    null,
  );

  return (
    <form action={formAction}>
      <button type="submit" disabled={isPending} className="sync-button">
        {isPending ? "Syncing catalog…" : "Sync latest catalog"}
      </button>
      {isPending && (
        <span className="sync-hint">
          Catalog update in progress — data will refresh shortly.
        </span>
      )}
      {state?.success && (
        <span className="sync-success">{state.message}</span>
      )}
      {state && !state.success && (
        <span className="sync-error">{state.message}</span>
      )}
    </form>
  );
}


